# Full hreflang block template (for a given slug)
def make_hreflang_block(slug):
    en_url = f"https://winnersclub.com/" if slug == 'index' else f"https://winnersclub.com/{slug}/"
    lines = []
    for lang, base_url in ALL_LOCALES_HREFLANG:
        if lang == 'en' or lang == 'x-default':
            href = en_url
        elif lang == 'pt-BR':
            s = '' if slug == 'index' else slug + '/'
            href = f"https://winnersclub.com/pt-br/{s}"
        else:
            lc = lang.lower()
            s = '' if slug == 'index' else slug + '/'
            href = f"https://winnersclub.com/{lc}/{s}"
        lines.append(f'  <link rel="alternate" hreflang="{lang}" href="{href}">')
    return '\n'.join(lines)

